'use client';

import { useState, useTransition } from 'react';
import { deleteBook } from '@/app/actions/admin';
import { Trash2, Loader2 } from 'lucide-react';

export default function DeleteBookButton({ id }: { id: string }) {
  const [isPending, startTransition] = useTransition();

  async function handleDelete() {
    if (confirm('Are you sure you want to delete this book? This action cannot be undone.')) {
      startTransition(async () => {
        await deleteBook(id);
      });
    }
  }

  return (
    <button 
      onClick={handleDelete}
      disabled={isPending}
      className="w-10 h-10 flex items-center justify-center text-red-500/60 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all border border-transparent hover:border-red-500/20 disabled:opacity-50"
      title="Delete Book"
    >
      {isPending ? (
        <Loader2 size={16} className="animate-spin" />
      ) : (
        <Trash2 size={16} />
      )}
    </button>
  );
}

