'use client';

import { useState, useTransition } from 'react';
import { addBook } from '@/app/actions/admin';
import { 
  Plus, 
  X, 
  BookOpen, 
  Save, 
  Loader2, 
  Sparkles, 
  User, 
  Tag, 
  Globe, 
  Type, 
  FileText, 
  Star, 
  Layout, 
  Link as LinkIcon 
} from 'lucide-react';

export default function AddBookForm() {
  const [open, setOpen] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setError(null);
    const form = e.currentTarget;
    const formData = new FormData(form);

    startTransition(async () => {
      const result = await addBook(formData);
      if (result.success) {
        form.reset();
        setOpen(false);
      } else {
        setError(result.error || 'Something went wrong.');
      }
    });
  }

  return (
    <>
      <button
        onClick={() => setOpen(true)}
        className="flex items-center gap-2 px-6 py-2.5 bg-saffron text-white rounded-xl hover:bg-saffron-dark transition-all font-bold text-sm shadow-[0_0_20px_rgba(245,158,11,0.3)] hover:shadow-[0_0_30px_rgba(245,158,11,0.5)] active:scale-95 group"
      >
        <Plus size={18} className="group-hover:rotate-90 transition-transform duration-300" />
        Add New Book
      </button>

      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-[#0A1A10]/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white/[0.03] border border-white/10 rounded-[2.5rem] w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col backdrop-blur-2xl shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-saffron/10 rounded-2xl flex items-center justify-center border border-saffron/20 shadow-[0_0_15px_rgba(245,158,11,0.1)]">
                  <BookOpen size={24} className="text-saffron" />
                </div>
                <div>
                  <h2 className="text-2xl font-bold font-heading text-white tracking-tight">Add New Book</h2>
                  <p className="text-white/40 text-xs font-medium italic">Expand the archive with sacred wisdom</p>
                </div>
              </div>
              <button
                onClick={() => setOpen(false)}
                className="w-10 h-10 flex items-center justify-center text-white/40 hover:text-white hover:bg-white/10 rounded-xl transition-all"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto scrollbar-hide">
              {error && (
                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm font-medium flex items-center gap-3">
                  <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse" />
                  {error}
                </div>
              )}

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                    Title
                  </label>
                  <div className="relative">
                    <Type size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                    <input
                      name="title"
                      required
                      placeholder="e.g. Bhagavad Gita"
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all shadow-inner"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                    Slug
                  </label>
                  <div className="relative">
                    <Layout size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                    <input
                      name="slug"
                      placeholder="auto-generated if blank"
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all font-mono text-xs"
                    />
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                    Author
                  </label>
                  <div className="relative">
                    <User size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                    <input
                      name="author"
                      placeholder="e.g. Vyasa"
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                    Genre
                  </label>
                  <div className="relative">
                    <Sparkles size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                    <input
                      name="genre"
                      placeholder="e.g. Scripture"
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all"
                    />
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                    Language
                  </label>
                  <div className="relative">
                    <Globe size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                    <select
                      name="language"
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white focus:outline-none focus:border-saffron/50 transition-all appearance-none cursor-pointer"
                    >
                      <option value="english" className="bg-[#0A1A10]">English</option>
                      <option value="sanskrit" className="bg-[#0A1A10]">Sanskrit</option>
                      <option value="hindi" className="bg-[#0A1A10]">Hindi</option>
                      <option value="telugu" className="bg-[#0A1A10]">Telugu</option>
                    </select>
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                    Status
                  </label>
                  <select
                    name="status"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-saffron/50 transition-all appearance-none cursor-pointer"
                  >
                    <option value="draft" className="bg-[#0A1A10]">Draft</option>
                    <option value="published" className="bg-[#0A1A10]">Published</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                    Cover Image URL
                  </label>
                  <div className="relative">
                    <LinkIcon size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                    <input
                      name="cover_url"
                      type="url"
                      placeholder="https://..."
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                    PDF URL
                  </label>
                  <div className="relative">
                    <FileText size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                    <input
                      name="pdf_url"
                      type="url"
                      placeholder="https://..."
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all"
                    />
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                  Summary
                </label>
                <textarea
                  name="summary"
                  rows={3}
                  placeholder="A brief essence of the book..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all resize-none text-sm"
                />
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-white/50 uppercase tracking-widest px-1">
                  Tags
                </label>
                <div className="relative">
                  <Tag size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                  <input
                    name="tags"
                    placeholder="advaita, vedanta, bhakti (comma separated)"
                    className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-3 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/50 transition-all text-sm"
                  />
                </div>
              </div>

              <div className="flex items-center gap-3 p-4 bg-white/5 rounded-2xl border border-white/10">
                <div className="w-10 h-10 bg-saffron/10 rounded-xl flex items-center justify-center border border-saffron/20">
                  <Star size={18} className="text-saffron" />
                </div>
                <div className="flex-1">
                  <p className="text-sm font-bold text-white">Featured Content</p>
                  <p className="text-[10px] text-white/40 uppercase tracking-wider font-medium">Highlight this book in the archive</p>
                </div>
                <label className="relative inline-flex items-center cursor-pointer">
                  <input type="checkbox" name="featured" value="true" className="sr-only peer" />
                  <div className="w-11 h-6 bg-white/10 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white/40 after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-saffron peer-checked:after:bg-white"></div>
                </label>
              </div>

              <div className="pt-6 flex justify-end gap-4 border-t border-white/5 bg-white/[0.01] -mx-8 -mb-8 p-8">
                <button
                  type="button"
                  onClick={() => setOpen(false)}
                  className="px-6 py-3 text-white/60 hover:text-white hover:bg-white/5 rounded-xl font-bold text-sm transition-all"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={isPending}
                  className="flex items-center gap-2 px-8 py-3 bg-saffron text-white rounded-xl hover:bg-saffron-dark font-bold text-sm transition-all disabled:opacity-50 shadow-[0_0_20px_rgba(245,158,11,0.2)] hover:shadow-[0_0_30px_rgba(245,158,11,0.4)] active:scale-95"
                >
                  {isPending ? (
                    <>
                      <Loader2 size={18} className="animate-spin" />
                      Saving...
                    </>
                  ) : (
                    <>
                      <Save size={18} />
                      Save Book
                    </>
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  );
}

